const arquivos = [
  { name: "Tabela de Precos 2024.pdf", mimeType: "application/pdf" },
  { name: "Manual Motor AP.pdf", mimeType: "application/pdf" }
];

// Injeta no contexto para a IA ver na próxima rodada
